        let mut ret = vec![];
        for _ in 0..cnt {
            ret.push(" ".to_string());
        }
        ret.join("")
    }

    let root_ptr = s.root_ptr();
    let mut frontier: Vec<(TrieNodeType, TrieHash, usize)> = vec![];
    let (root, root_hash) = Trie::read_root(s).unwrap();
